DROP TABLE IF EXISTS `exam_assignments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `exam_assignments` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int unsigned NOT NULL COMMENT '所属课程',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '考试标题',
  `exam_type` enum('midterm','final','quiz','other') COLLATE utf8mb4_unicode_ci DEFAULT 'quiz' COMMENT '考试类型',
  `full_score` decimal(5,2) DEFAULT '100.00' COMMENT '满分',
  `start_time` datetime DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
  `duration` int DEFAULT NULL COMMENT '考试时长(分钟)',
  `status` tinyint DEFAULT '1' COMMENT '状态',
  `raw_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原始数据ID',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_course` (`course_id`),
  KEY `idx_type` (`exam_type`),
  CONSTRAINT `exam_assignments_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='考试任务表';
/*!40101 SET character_set_client = @saved_cs_client */;

