--

DROP TABLE IF EXISTS `exam_results`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `exam_results` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `exam_id` int unsigned NOT NULL COMMENT '考试任务ID',
  `student_id` int unsigned NOT NULL COMMENT '学生ID',
  `score` decimal(5,2) DEFAULT NULL COMMENT '得分',
  `submit_time` datetime DEFAULT NULL COMMENT '提交时间',
  `is_submitted` tinyint DEFAULT '1' COMMENT '是否提交',
  `correct_count` int DEFAULT NULL COMMENT '答对题数',
  `total_count` int DEFAULT NULL COMMENT '总题数',
  `raw_data` json DEFAULT NULL COMMENT '原始答案数据',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_exam_student` (`exam_id`,`student_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_score` (`score`),
