--
-- Table structure for table `import_logs`
--

DROP TABLE IF EXISTS `import_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `import_logs` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `import_type` varchar(20) NOT NULL COMMENT '瀵煎叆绫诲瀷:activities/homework/exams/enrollments',
  `file_name` varchar(255) NOT NULL COMMENT '鏂囦欢鍚',
  `file_size` int DEFAULT '0' COMMENT '鏂囦欢澶у皬(瀛楄妭)',
  `uploaded_by` int unsigned DEFAULT NULL COMMENT '涓婁紶鑰匢D',
  `course_id` int unsigned DEFAULT NULL COMMENT '鍏宠仈璇剧▼ID',
  `total_rows` int DEFAULT '0' COMMENT '鎬昏?鏁',
  `success_rows` int DEFAULT '0' COMMENT '鎴愬姛琛屾暟',
  `failed_rows` int DEFAULT '0' COMMENT '澶辫触琛屾暟',
  `status` varchar(20) DEFAULT 'pending' COMMENT '鐘舵?:pending/success/partial/failed',
  `error_message` text COMMENT '閿欒?淇℃伅',
  `details` json DEFAULT NULL COMMENT '璇︾粏淇℃伅',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_import_type` (`import_type`),
  KEY `idx_course_id` (`course_id`),
  KEY `idx_status` (`status`),
  KEY `idx_uploaded_by` (`uploaded_by`),
  CONSTRAINT `import_logs_ibfk_1` FOREIGN KEY (`uploaded_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='鏁版嵁瀵煎叆璁板綍琛';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `import_logs`
--

LOCK TABLES `import_logs` WRITE;
/*!40000 ALTER TABLE `import_logs` DISABLE KEYS */;
/*!40000 ALTER TABLE `import_logs` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `intervention_records`
--

DROP TABLE IF EXISTS `intervention_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `intervention_records` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `warning_id` int unsigned DEFAULT NULL COMMENT '关联预警ID',
  `student_id` int unsigned NOT NULL COMMENT '学生ID',
  `course_id` int unsigned DEFAULT NULL COMMENT '关联课程',
  `intervenor_id` int unsigned NOT NULL COMMENT '干预人ID(辅导员/教师)',
