-- Table structure for table `student_course_scores`
--

DROP TABLE IF EXISTS `student_course_scores`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_course_scores` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `student_id` int unsigned NOT NULL COMMENT '学生ID',
  `course_id` int unsigned NOT NULL COMMENT '课程ID',
  `attendance_rate` decimal(5,2) DEFAULT NULL COMMENT '出勤率',
  `video_progress` decimal(5,2) DEFAULT NULL COMMENT '视频进度',
  `homework_avg` decimal(5,2) DEFAULT NULL COMMENT '作业平均分',
  `homework_submit_rate` decimal(5,2) DEFAULT NULL COMMENT '作业提交率',
  `exam_avg` decimal(5,2) DEFAULT NULL COMMENT '考试平均分',
  `knowledge_mastery` decimal(5,2) DEFAULT NULL COMMENT '知识点掌握度',
  `final_score` decimal(5,2) DEFAULT NULL COMMENT '期末成绩(如果有)',
  `last_calculated` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最后计算时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_student_course` (`student_id`,`course_id`),
  KEY `idx_course` (`course_id`),
  CONSTRAINT `student_course_scores_ibfk_1` FOREIGN KEY (`student_id`) REFERENCES `students` (`id`) ON DELETE CASCADE,
  CONSTRAINT `student_course_scores_ibfk_2` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1063 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学生课程综合得分表';
/*!40101 SET character_set_client = @saved_cs_client */;

