--
-- Table structure for table `students`
--

DROP TABLE IF EXISTS `students`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `students` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `student_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '学号',
  `name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '姓名',
  `gender` tinyint DEFAULT '0' COMMENT '性别: 0未知, 1男, 2女',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '手机号',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '邮箱',
  `class_id` int unsigned DEFAULT NULL COMMENT '班级ID',
  `major_id` int unsigned DEFAULT NULL COMMENT '专业ID',
  `enrollment_year` year DEFAULT NULL COMMENT '入学年份',
  `status` tinyint DEFAULT '1' COMMENT '状态: 0离校, 1在读',
  `raw_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原始数据ID(用于追溯)',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `student_no` (`student_no`),
  KEY `major_id` (`major_id`),
  KEY `idx_student_no` (`student_no`),
  KEY `idx_class` (`class_id`),
  KEY `idx_name` (`name`),
  CONSTRAINT `students_ibfk_1` FOREIGN KEY (`class_id`) REFERENCES `classes` (`id`) ON DELETE SET NULL,
  CONSTRAINT `students_ibfk_2` FOREIGN KEY (`major_id`) REFERENCES `majors` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=358 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学生信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

