--
-- Table structure for table `warning_records`
--

DROP TABLE IF EXISTS `warning_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `warning_records` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `student_id` int unsigned NOT NULL COMMENT '学生ID',
  `course_id` int unsigned DEFAULT NULL COMMENT '课程ID(为空表示综合预警)',
  `risk_level` enum('high','medium','low','normal') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '风险等级: high红, medium橙, low黄, normal正常',
  `composite_score` decimal(5,2) DEFAULT NULL COMMENT '综合得分',
  `attendance_score` decimal(5,2) DEFAULT NULL COMMENT '出勤率得分',
  `progress_score` decimal(5,2) DEFAULT NULL COMMENT '学习进度得分',
  `homework_score` decimal(5,2) DEFAULT NULL COMMENT '作业成绩得分',
  `exam_score` decimal(5,2) DEFAULT NULL COMMENT '考试成绩得分',
  `ai_analysis` text COLLATE utf8mb4_unicode_ci COMMENT 'AI问题分析',
  `ai_suggestions` json DEFAULT NULL COMMENT 'AI建议列表',
  `ai_parent_script` text COLLATE utf8mb4_unicode_ci COMMENT 'AI家长沟通文案',
  `ai_encouragement` text COLLATE utf8mb4_unicode_ci COMMENT 'AI激励信',
  `ai_source` enum('ai','template') COLLATE utf8mb4_unicode_ci DEFAULT 'template' COMMENT '建议来源',
  `status` enum('active','resolved','ignored') COLLATE utf8mb4_unicode_ci DEFAULT 'active' COMMENT '预警状态',
  `resolved_at` datetime DEFAULT NULL COMMENT '解决时间',
  `resolved_by` int unsigned DEFAULT NULL COMMENT '处理人ID',
  `resolve_note` text COLLATE utf8mb4_unicode_ci COMMENT '处理备注',
  `calculation_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '计算时间',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `resolved_by` (`resolved_by`),
  KEY `idx_student` (`student_id`),
  KEY `idx_course` (`course_id`),
  KEY `idx_risk_level` (`risk_level`),
  KEY `idx_status` (`status`),
  KEY `idx_calc_time` (`calculation_time`),
  CONSTRAINT `warning_records_ibfk_1` FOREIGN KEY (`student_id`) REFERENCES `students` (`id`) ON DELETE CASCADE,
  CONSTRAINT `warning_records_ibfk_2` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE,
  CONSTRAINT `warning_records_ibfk_3` FOREIGN KEY (`resolved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2145 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='预警记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

